-//! Draft Model Downloader
-//!
-//! Automatically downloads small draft models for speculative decoding.
-//! For MoE models (Mixtral), downloads a fast small model (Qwen-0.5B).
-//! For dense models, can requantize to Q2_K instead.
-
-const std = @import("std");
-const profile = @import("profile.zig");
-
-const log = std.log.scoped(.draft_downloader);
-
-/// Draft model configurations for different target models
-pub const DraftModelConfig = struct {
-    name: []const u8,
-    url: []const u8,
-    size_gb: f32,
-    filename: []const u8,
-};
-
-/// Get recommended draft model for a given target model
-pub fn getRecommendedDraft(model_info: profile.ModelInfo) ?DraftModelConfig {
-    // MoE models need external draft (can't requantize MoE easily)
-    if (model_info.n_expert > 0) {
-        // Qwen2.5-0.5B is tiny (400MB) and fast
-        return DraftModelConfig{
-            .name = "Qwen2.5-0.5B-Instruct-Q4_K_M",
-            .url = "https://huggingface.co/Qwen/Qwen2.5-0.5B-Instruct-GGUF/resolve/main/qwen2.5-0.5b-instruct-q4_k_m.gguf",
-            .size_gb = 0.4,
-            .filename = "qwen2.5-0.5b-instruct-q4_k_m.gguf",
-        };
-    }
-
-    // Dense models > 20GB could benefit from a draft
-    if (model_info.size_gb > 20.0) {
-        return DraftModelConfig{
-            .name = "Qwen2.5-0.5B-Instruct-Q4_K_M",
-            .url = "https://huggingface.co/Qwen/Qwen2.5-0.5B-Instruct-GGUF/resolve/main/qwen2.5-0.5b-instruct-q4_k_m.gguf",
-            .size_gb = 0.4,
-            .filename = "qwen2.5-0.5b-instruct-q4_k_m.gguf",
-        };
-    }
-
-    return null;
-}
-
-/// Get the cache directory for draft models
-pub fn getDraftCacheDir(allocator: std.mem.Allocator) ![]u8 {
-    const home = std.posix.getenv("HOME") orelse return error.NoHomeDir;
-    return std.fmt.allocPrint(allocator, "{s}/.cache/zell/drafts", .{home});
-}
-
-/// Get full path for a draft model
-pub fn getDraftPath(allocator: std.mem.Allocator, filename: []const u8) ![]u8 {
-    const cache_dir = try getDraftCacheDir(allocator);
-    defer allocator.free(cache_dir);
-    return std.fmt.allocPrint(allocator, "{s}/{s}", .{ cache_dir, filename });
-}
-
-/// Check if draft model already exists and is valid
-pub fn isDraftCached(allocator: std.mem.Allocator, config: DraftModelConfig) bool {
-    const path = getDraftPath(allocator, config.filename) catch return false;
-    defer allocator.free(path);
-
-    const file = std.fs.cwd().openFile(path, .{}) catch return false;
-    defer file.close();
-
-    const stat = file.stat() catch return false;
-    const size_gb = @as(f32, @floatFromInt(stat.size)) / (1024.0 * 1024.0 * 1024.0);
-
-    // Check if file size is reasonable (within 20% of expected)
-    const min_size = config.size_gb * 0.8;
-    const max_size = config.size_gb * 1.2;
-    return size_gb >= min_size and size_gb <= max_size;
-}
-
-/// Download draft model using curl
-pub fn downloadDraft(allocator: std.mem.Allocator, config: DraftModelConfig) ![]u8 {
-    const cache_dir = try getDraftCacheDir(allocator);
-    defer allocator.free(cache_dir);
-
-    // Create cache directory
-    std.fs.cwd().makePath(cache_dir) catch |err| {
-        if (err != error.PathAlreadyExists) return err;
-    };
-
-    const output_path = try getDraftPath(allocator, config.filename);
-    errdefer allocator.free(output_path);
-
-    // Check if already downloaded
-    if (isDraftCached(allocator, config)) {
-        log.info("Draft model already cached: {s}", .{output_path});
-        return output_path;
-    }
-
-    std.debug.print("📥 Downloading draft model: {s}\n", .{config.name});
-    std.debug.print("   URL: {s}\n", .{config.url});
-    std.debug.print("   Size: ~{d:.1} GB\n", .{config.size_gb});
-    std.debug.print("   Saving to: {s}\n", .{output_path});
-
-    // Use curl to download (most reliable cross-platform)
-    const result = std.process.Child.run(.{
-        .allocator = allocator,
-        .argv = &[_][]const u8{
-            "curl",
-            "-L",           // Follow redirects
-            "-#",           // Progress bar
-            "--fail",       // Fail on HTTP errors
-            "-o",
-            output_path,
-            config.url,
-        },
-    });
-
-    if (result) |res| {
-        defer allocator.free(res.stdout);
-        defer allocator.free(res.stderr);
-
-        if (res.term.Exited == 0) {
-            std.debug.print("   ✅ Download complete!\n\n", .{});
-            return output_path;
-        } else {
-            std.debug.print("   ❌ Download failed: {s}\n", .{res.stderr});
-            return error.DownloadFailed;
-        }
-    } else |err| {
-        std.debug.print("   ❌ Failed to run curl: {}\n", .{err});
-        return err;
-    }
-}
-
-/// Ensure draft model is available, downloading if necessary
-pub fn ensureDraftModel(allocator: std.mem.Allocator, model_info: profile.ModelInfo) !?[]u8 {
-    const config = getRecommendedDraft(model_info) orelse return null;
-
-    if (isDraftCached(allocator, config)) {
-        const path = try getDraftPath(allocator, config.filename);
-        log.info("Using cached draft model: {s}", .{path});
-        return path;
-    }
-
-    return try downloadDraft(allocator, config);
-}
-
-test "getDraftCacheDir" {
-    const allocator = std.testing.allocator;
-    const dir = try getDraftCacheDir(allocator);
-    defer allocator.free(dir);
-    try std.testing.expect(std.mem.endsWith(u8, dir, "/.cache/zell/drafts"));
-}

